import React, { useEffect, useRef, useState } from 'react';

/* ─── Design tokens ─── */
const BG      = '#07070A';
const CARD    = '#111114';
const BORDER  = 'rgba(255,255,255,0.08)';
const CYAN    = '#22D3EE';
const PURPLE  = '#8B5CF6';
const WHITE   = '#F8FAFC';
const MUTED   = '#64748B';
const MUTED2  = '#94A3B8';

/* ─── Scroll-reveal hook ─── */
function useReveal() {
  useEffect(() => {
    const obs = new IntersectionObserver(
      (entries) => entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); }),
      { threshold: 0.12 }
    );
    document.querySelectorAll('.reveal').forEach(el => obs.observe(el));
    return () => obs.disconnect();
  }, []);
}

/* ─── Animated hero memory graph ─── */
const MemoryGraph = () => {
  const nodes = [
    { x: 200, y: 80,  label: 'User',    delay: 0 },
    { x: 380, y: 40,  label: 'Agent A', delay: 0.3 },
    { x: 380, y: 120, label: 'Agent B', delay: 0.6 },
    { x: 560, y: 80,  label: 'Memory',  delay: 0.9 },
    { x: 560, y: 160, label: 'Context', delay: 1.2 },
    { x: 740, y: 100, label: 'Output',  delay: 1.5 },
  ];
  const edges = [
    [0,1],[0,2],[1,3],[2,3],[3,4],[3,5],[4,5],
  ];
  return (
    <svg viewBox="0 0 900 240" className="w-full h-48 sm:h-64" style={{ overflow: 'visible' }}>
      <defs>
        <radialGradient id="node-cyan" cx="50%" cy="50%" r="50%">
          <stop offset="0%" stopColor={CYAN} stopOpacity="0.3" />
          <stop offset="100%" stopColor={CYAN} stopOpacity="0" />
        </radialGradient>
        <radialGradient id="node-purple" cx="50%" cy="50%" r="50%">
          <stop offset="0%" stopColor={PURPLE} stopOpacity="0.3" />
          <stop offset="100%" stopColor={PURPLE} stopOpacity="0" />
        </radialGradient>
        <filter id="glow-c">
          <feGaussianBlur stdDeviation="3" result="blur" />
          <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
        </filter>
      </defs>

      {/* Edges */}
      {edges.map(([a,b], i) => (
        <line
          key={i}
          x1={nodes[a].x} y1={nodes[a].y}
          x2={nodes[b].x} y2={nodes[b].y}
          stroke={i % 2 === 0 ? CYAN : PURPLE}
          strokeWidth="1"
          strokeOpacity="0.25"
          strokeDasharray="4 4"
          style={{ animation: `line-draw 1.4s ${0.2 * i}s ease-out both` }}
        />
      ))}

      {/* Nodes */}
      {nodes.map((n, i) => {
        const color = i === 3 ? CYAN : i === 0 ? WHITE : PURPLE;
        return (
          <g key={i} style={{ animationDelay: `${n.delay}s` }}>
            <circle cx={n.x} cy={n.y} r="28" fill={color} fillOpacity="0.06" />
            <circle
              cx={n.x} cy={n.y} r="10"
              fill={color} fillOpacity="0.15"
              stroke={color} strokeWidth="1.5"
              filter="url(#glow-c)"
              className="node-pulse"
              style={{ animationDelay: `${n.delay}s` }}
            />
            <circle cx={n.x} cy={n.y} r="4" fill={color} />
            <text
              x={n.x} y={n.y + 26}
              fill={color} fillOpacity="0.7"
              fontSize="11" textAnchor="middle"
              fontFamily="SF Mono, Fira Code, monospace"
            >
              {n.label}
            </text>
          </g>
        );
      })}
    </svg>
  );
};

/* ─── Code snippet ─── */
const CodeSnippet = () => {
  const [copied, setCopied] = useState(false);
  const code = `import { GlassMem } from 'glassmem'

const memory = new GlassMem({
  apiKey: process.env.GLASSMEM_API_KEY
})

// Store what the agent learns
await memory.remember(userId, {
  preference: "Vegetarian",
  context:    "Allergic to nuts",
  expires:    "7d"
})

// Recall before every inference
const ctx = await memory.recall(userId)
// → { preference: "Vegetarian", ... }`;

  const highlight = (line) => {
    if (line.startsWith('//')) return <span style={{ color: MUTED }}>{line}</span>;
    if (line.startsWith('import')) return (
      <span>
        <span style={{ color: PURPLE }}>import</span>
        <span style={{ color: MUTED2 }}> {'{ GlassMem }'} </span>
        <span style={{ color: PURPLE }}>from</span>
        <span style={{ color: '#86EFAC' }}> 'glassmem'</span>
      </span>
    );
    if (line.includes('new GlassMem')) return (
      <span>
        <span style={{ color: '#38BDF8' }}>const</span>
        <span style={{ color: MUTED2 }}> memory = </span>
        <span style={{ color: '#34D399' }}>new</span>
        <span style={{ color: CYAN }}> GlassMem</span>
        <span style={{ color: MUTED2 }}>{'({'}</span>
      </span>
    );
    if (line.includes('await memory.remember')) return (
      <span>
        <span style={{ color: PURPLE }}>await</span>
        <span style={{ color: MUTED2 }}> memory.</span>
        <span style={{ color: CYAN }}>remember</span>
        <span style={{ color: MUTED2 }}>(userId, {'{'}</span>
      </span>
    );
    if (line.includes('await memory.recall')) return (
      <span>
        <span style={{ color: '#38BDF8' }}>const</span>
        <span style={{ color: MUTED2 }}> ctx = </span>
        <span style={{ color: PURPLE }}>await</span>
        <span style={{ color: MUTED2 }}> memory.</span>
        <span style={{ color: CYAN }}>recall</span>
        <span style={{ color: MUTED2 }}>(userId)</span>
      </span>
    );
    return <span style={{ color: MUTED2 }}>{line}</span>;
  };

  return (
    <div
      className="rounded-xl overflow-hidden border relative"
      style={{ backgroundColor: '#0D0D10', borderColor: BORDER }}
    >
      {/* Window chrome */}
      <div
        className="flex items-center justify-between px-4 py-3 border-b"
        style={{ borderColor: BORDER, backgroundColor: '#0A0A0D' }}
      >
        <div className="flex items-center gap-2">
          <span className="w-3 h-3 rounded-full bg-red-500/70" />
          <span className="w-3 h-3 rounded-full bg-yellow-400/70" />
          <span className="w-3 h-3 rounded-full bg-emerald-400/70" />
          <span className="font-mono text-[11px] ml-2" style={{ color: MUTED }}>agent.ts</span>
        </div>
        <button
          onClick={() => { navigator.clipboard?.writeText(code); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
          className="font-mono text-[11px] px-2 py-1 rounded transition-colors"
          style={{ color: copied ? CYAN : MUTED, border: `1px solid ${BORDER}` }}
        >
          {copied ? 'copied!' : 'copy'}
        </button>
      </div>
      {/* Code */}
      <div className="px-5 py-4 code-block overflow-x-auto">
        {code.split('\n').map((line, i) => (
          <div key={i} className="flex">
            <span className="select-none mr-5 text-right w-5 flex-shrink-0" style={{ color: MUTED, opacity: 0.4, fontSize: 11 }}>{i + 1}</span>
            <span>{highlight(line)}</span>
          </div>
        ))}
      </div>
      {/* Cyan glow at bottom */}
      <div
        className="pointer-events-none absolute bottom-0 left-0 right-0 h-16"
        style={{ background: `linear-gradient(to top, rgba(34,211,238,0.05), transparent)` }}
      />
    </div>
  );
};

/* ─── Section wrapper ─── */
const Section = ({ id, children, className = '', style = {} }) => (
  <section id={id} className={`py-24 sm:py-32 ${className}`} style={style}>
    <div className="max-w-6xl mx-auto px-6 sm:px-8">{children}</div>
  </section>
);

/* ─── Eyebrow label ─── */
const Label = ({ children, color = CYAN }) => (
  <p className="font-mono text-[11px] font-semibold tracking-[0.22em] uppercase mb-5" style={{ color }}>
    {children}
  </p>
);

/* ─── Card ─── */
const Card = ({ children, className = '', glowColor = null, style = {} }) => (
  <div
    className={`rounded-2xl p-6 border transition-all duration-300 ${className}`}
    style={{
      backgroundColor: CARD,
      borderColor: BORDER,
      ...(glowColor ? { '--glow': glowColor } : {}),
      ...style,
    }}
    onMouseEnter={e => {
      if (glowColor) e.currentTarget.style.boxShadow = `0 0 30px ${glowColor}22, 0 0 60px ${glowColor}11`;
      e.currentTarget.style.borderColor = glowColor ? `${glowColor}44` : 'rgba(255,255,255,0.14)';
    }}
    onMouseLeave={e => {
      e.currentTarget.style.boxShadow = '';
      e.currentTarget.style.borderColor = BORDER;
    }}
  >
    {children}
  </div>
);

/* ═══════════════════════════════════════════════
   NAVBAR
═══════════════════════════════════════════════ */
const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);

  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', h);
    return () => window.removeEventListener('scroll', h);
  }, []);

  const scroll = (id) => {
    setOpen(false);
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <header
      className="fixed top-0 left-0 right-0 z-50 transition-all duration-300"
      style={{
        background: scrolled ? 'rgba(7,7,10,0.92)' : 'transparent',
        backdropFilter: scrolled ? 'blur(16px)' : 'none',
        borderBottom: scrolled ? `1px solid ${BORDER}` : '1px solid transparent',
      }}
    >
      <nav className="max-w-6xl mx-auto px-6 sm:px-8">
        <div className="flex items-center justify-between h-16">
          {/* Logo */}
          <div className="flex items-center gap-2.5">
            <div
              className="w-8 h-8 rounded-lg flex items-center justify-center font-bold text-[12px] font-mono"
              style={{
                background: `linear-gradient(135deg, ${CYAN}33, ${PURPLE}33)`,
                border: `1px solid ${CYAN}44`,
                color: CYAN,
              }}
            >
              GM
            </div>
            <span className="font-bold text-[15px] tracking-[-0.02em]" style={{ color: WHITE }}>
              GlassMem<span style={{ color: CYAN }}>.ai</span>
            </span>
          </div>

          {/* Desktop links */}
          <div className="hidden md:flex items-center gap-1">
            {[['Docs', 'docs'], ['Problems', 'problem'], ['Solution', 'solution'], ['Pricing', 'pricing']].map(([label, id]) => (
              <button
                key={id}
                onClick={() => scroll(id)}
                className="text-[13px] px-3 py-1.5 rounded-lg transition-colors font-medium"
                style={{ color: MUTED2 }}
                onMouseEnter={e => (e.currentTarget.style.color = WHITE)}
                onMouseLeave={e => (e.currentTarget.style.color = MUTED2)}
              >
                {label}
              </button>
            ))}
            <a
              href="#cta"
              onClick={e => { e.preventDefault(); scroll('cta'); }}
              className="ml-4 inline-flex items-center gap-2 font-semibold px-4 py-2 rounded-lg text-[13px] transition-all"
              style={{
                background: `linear-gradient(135deg, ${CYAN}22, ${PURPLE}22)`,
                border: `1px solid ${CYAN}44`,
                color: CYAN,
              }}
              onMouseEnter={e => (e.currentTarget.style.background = `linear-gradient(135deg, ${CYAN}33, ${PURPLE}33)`)}
              onMouseLeave={e => (e.currentTarget.style.background = `linear-gradient(135deg, ${CYAN}22, ${PURPLE}22)`)}
            >
              Start Building
              <span className="opacity-60">→</span>
            </a>
          </div>

          {/* Mobile */}
          <button className="md:hidden text-[22px] transition-colors" style={{ color: MUTED2 }} onClick={() => setOpen(!open)}>
            {open ? '✕' : '☰'}
          </button>
        </div>

        {open && (
          <div className="md:hidden py-4 border-t space-y-1" style={{ borderColor: BORDER }}>
            {[['Docs', 'docs'], ['Problem', 'problem'], ['Solution', 'solution'], ['Pricing', 'pricing']].map(([label, id]) => (
              <button key={id} onClick={() => scroll(id)} className="block w-full text-left px-3 py-2.5 rounded-lg text-[14px]" style={{ color: MUTED2 }}>
                {label}
              </button>
            ))}
            <button onClick={() => scroll('cta')} className="block w-full text-left px-3 py-2.5 mt-2 rounded-lg font-semibold text-[14px]" style={{ color: CYAN, border: `1px solid ${CYAN}44` }}>
              Start Building →
            </button>
          </div>
        )}
      </nav>
    </header>
  );
};

/* ═══════════════════════════════════════════════
   HERO
═══════════════════════════════════════════════ */
const Hero = () => (
  <section
    className="relative min-h-screen flex flex-col justify-center pt-24 pb-16 grid-bg overflow-hidden"
    style={{ background: BG }}
  >
    {/* Background glows */}
    <div className="pointer-events-none absolute inset-0 overflow-hidden">
      <div className="absolute -top-40 left-1/2 -translate-x-1/2 w-[800px] h-[500px] rounded-full glow-shift"
        style={{ background: `radial-gradient(ellipse, ${CYAN}0D 0%, transparent 70%)` }} />
      <div className="absolute top-1/3 -left-40 w-[600px] h-[600px] rounded-full glow-shift"
        style={{ background: `radial-gradient(ellipse, ${PURPLE}0A 0%, transparent 70%)`, animationDelay: '1.5s' }} />
      <div className="absolute bottom-0 right-0 w-[500px] h-[500px] rounded-full"
        style={{ background: `radial-gradient(ellipse, ${CYAN}08 0%, transparent 70%)` }} />
    </div>

    <div className="max-w-6xl mx-auto px-6 sm:px-8 relative z-10 w-full">
      {/* Badge */}
      <div className="flex justify-center mb-10 fade-up" style={{ animationDelay: '0s' }}>
        <div
          className="inline-flex items-center gap-2 px-4 py-2 rounded-full font-mono text-[11px] font-semibold tracking-[0.15em]"
          style={{ background: `${CYAN}11`, border: `1px solid ${CYAN}33`, color: CYAN }}
        >
          <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 glow-shift" />
          MEMORY INFRASTRUCTURE FOR THE AGENTIC ERA
        </div>
      </div>

      {/* Headline */}
      <div className="text-center mb-6 fade-up" style={{ animationDelay: '0.1s' }}>
        <h1
          className="font-bold leading-[0.95] tracking-[-0.04em]"
          style={{
            fontSize: 'clamp(52px, 8vw, 96px)',
            color: WHITE,
          }}
        >
          Your Agents
          <br />
          <span style={{
            background: `linear-gradient(135deg, ${CYAN}, ${PURPLE})`,
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
          }}>
            Finally Remember.
          </span>
        </h1>
      </div>

      {/* Subheadline */}
      <p
        className="text-center text-[17px] sm:text-[19px] leading-relaxed max-w-2xl mx-auto mb-10 fade-up"
        style={{ color: MUTED2, animationDelay: '0.2s' }}
      >
        Persistent, temporal, cross-session memory for AI agents.
        No massive prompts. No RAG pipelines. No vector tuning.
        Just <span style={{ color: WHITE, fontWeight: 600 }}>plug it in.</span>
      </p>

      {/* CTAs */}
      <div className="flex flex-col sm:flex-row gap-4 justify-center mb-16 fade-up" style={{ animationDelay: '0.3s' }}>
        <button
